async function init(){var ssrEl=document.getElementById('ssr-content');if(ssrEl){ssrEl.style.visibility='hidden';ssrEl.style.height='0';ssrEl.style.overflow='hidden';}if(loadingEl)loadingEl.classList.remove('hidden');try{const toolResp=await fetch('/api/v1/tools/'+encodeURIComponent(slug));if(!toolResp.ok){throw new Error(slug+' は登録されていないか、データが取得できませんでした。');}
const tool=await toolResp.json();let scores=null;try{const scoreResp=await fetch('/api/v1/scores/'+encodeURIComponent(slug));if(scoreResp.ok){scores=await scoreResp.json();}}catch(e){}
let industries=[],useCaseTags=[],govData=null,analysisData=null;try{const[indResp,ucResp,govResp,analysisResp]=await Promise.all([fetch('/api/v1/industries/tools/'+tool.id+'/industries'),fetch('/api/v1/industries/tools/'+tool.id+'/use-cases'),fetch('/api/v1/risk-governance/tools/'+tool.id),fetch('/api/v1/scores/'+encodeURIComponent(slug)+'/analysis'),]);if(indResp.ok)industries=await indResp.json();if(ucResp.ok)useCaseTags=await ucResp.json();if(govResp.ok)govData=await govResp.json();if(analysisResp.ok)analysisData=await analysisResp.json();}catch(e){}
/* Critical path: paint above-the-fold (hero + radar) synchronously,
   then yield to the browser so it can render them before we run the
   below-the-fold work. This is a time-sliced "code split" — no extra
   HTTP request, but TTI drops because the long render chain no longer
   blocks the first paint. */
renderHero(tool,scores);renderAuditMeta(analysisData);renderExecutiveSummary(tool);renderScoreDashboard(scores);renderPositioning(analysisData&&analysisData.positioning,scores);showMain();var _idle=window.requestIdleCallback||function(f){return setTimeout(f,1);};_idle(function(){renderToolInfo(tool);renderPrerequisites(tool,govData);renderIndustryFit(industries,useCaseTags);renderSEOSections(tool);renderAnalysisReport(scores,analysisData);document.querySelectorAll('.axis-expand-btn').forEach(function(btn){btn.addEventListener('click',function(){var panel=this.parentElement.querySelector('.expand-panel');panel.classList.toggle('hidden');var isHidden=panel.classList.contains('hidden');this.querySelector('.expand-label').textContent=isHidden?'詳細を表示':'閉じる';this.querySelector('.expand-icon').style.transform=isHidden?'':'rotate(180deg)';});});renderGovernance(govData);renderIndustryUseCaseTags(industries,useCaseTags);renderScoreHistory(slug);renderRelatedTools(tool);});}catch(e){showError(e.message||'データの取得に失敗しました。');}}
